def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)
    middle_index = (n - 1) // 2
    min_idx, max_idx = 0, n-1

    while min_idx < middle_index or max_idx > middle_index:
        if nums[min_idx + 1] == nums[min_idx]:
            min_idx += 1
        else:
            break
        if nums[max_idx - 1] == nums[max_idx]:
            max_idx -= 1
        else:
            break

    trimmed_nums = nums[:min_idx] + nums[max_idx+1:]
    return sum(trimmed_nums) / len(trimmed_nums)
